import os
from google.cloud import storage, firestore, pubsub_v1
from google.auth import compute_engine
from google.auth.transport.requests import Request

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Environment variables
PROJECT_ID = os.environ['GCP_PROJECT']
TOPIC_NAME = os.environ['PUBSUB_TOPIC']

def process_file(data, context):
    bucket_name = data['bucket']
    file_name = data['name']

    # Download file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_content = blob.download_as_text()

    # Process file content and write to Firestore
    doc_ref = firestore_client.collection('processed_files').document(file_name)
    doc_ref.set({'content': file_content})

    # Publish message to Pub/Sub
    topic_path = publisher.topic_path(PROJECT_ID, TOPIC_NAME)
    publisher.publish(topic_path, data=file_content.encode('utf-8'), filename=file_name)

# Assign service account with necessary permissions
def assign_service_account():
    credentials = compute_engine.Credentials()
    credentials.refresh(Request())
    # Ensure the service account has the necessary roles:
    # roles/storage.admin, roles/datastore.user, roles/pubsub.publisher
    # This is typically done via IAM in the GCP console, not programmatically in the function.

# Ensure the function is deployed with the correct service account
assign_service_account()